INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('What is the SI unit of force?', '["Newton (N)", "Joule (J)", "Pascal (Pa)", "Watt (W)"]', 'A', 'The SI unit of force is the Newton (N). One Newton equals the force needed to accelerate 1 kg of mass at 1 m/s².', 'Science', 'Physics', 'easy', 'secondary'),
('Newton''s First Law of Motion states that an object at rest will remain at rest unless acted upon by a(n):', '["Unbalanced force", "Balanced force", "Equal and opposite force", "Gravitational force"]', 'A', 'Newton''s First Law (Law of Inertia) states an object at rest stays at rest, and an object in motion stays in motion, unless acted on by an unbalanced (net) external force.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the formula for calculating speed?', '["Speed = Distance ÷ Time", "Speed = Distance × Time", "Speed = Force ÷ Mass", "Speed = Mass × Acceleration"]', 'A', 'Speed = Distance / Time. Speed measures how fast an object moves, typically in meters per second (m/s).', 'Science', 'Physics', 'easy', 'secondary'),
('Newton''s Second Law of Motion is expressed as:', '["F = ma", "F = mv", "F = m/a", "F = m + a"]', 'A', 'Newton''s Second Law states Force = mass × acceleration (F = ma). The acceleration of an object is directly proportional to the net force acting on it.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the SI unit of energy?', '["Joule (J)", "Newton (N)", "Watt (W)", "Pascal (Pa)"]', 'A', 'The joule (J) is the SI unit of energy. One joule equals one Newton-meter (N·m) or one kilogram-meter squared per second squared (kg·m²/s²).', 'Science', 'Physics', 'easy', 'secondary'),
('What type of energy does a moving object possess?', '["Kinetic energy", "Potential energy", "Chemical energy", "Thermal energy"]', 'A', 'Kinetic energy is the energy of motion. Any moving object has kinetic energy: KE = ½mv².', 'Science', 'Physics', 'easy', 'secondary'),
('What type of energy is stored in an object due to its position or height?', '["Gravitational potential energy", "Kinetic energy", "Elastic potential energy", "Nuclear energy"]', 'A', 'Gravitational potential energy is stored energy based on an object''s height above a reference point: PE = mgh.', 'Science', 'Physics', 'easy', 'secondary'),
('Newton''s Third Law of Motion states that for every action, there is an equal and opposite:', '["Reaction", "Force", "Acceleration", "Motion"]', 'A', 'Newton''s Third Law states: For every action, there is an equal and opposite reaction. Forces always come in pairs.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the unit of electrical resistance?', '["Ohm (Ω)", "Volt (V)", "Ampere (A)", "Watt (W)"]', 'A', 'The ohm (Ω) is the SI unit of electrical resistance. It measures how much a material opposes the flow of electric current.', 'Science', 'Physics', 'easy', 'secondary'),
('According to Ohm''s Law, what is the relationship between voltage (V), current (I), and resistance (R)?', '["V = IR", "V = I/R", "V = I + R", "V = I - R"]', 'A', 'Ohm''s Law: V = IR. Voltage equals current multiplied by resistance. This relationship holds for ohmic (linear) conductors.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the term for the rate at which work is done?', '["Power", "Energy", "Force", "Momentum"]', 'A', 'Power is the rate at which work is done or energy is transferred: P = W/t. The SI unit of power is the watt (W).', 'Science', 'Physics', 'easy', 'secondary'),
('What happens to the frequency of a sound wave as it moves toward a listener? (Doppler effect)', '["It increases", "It decreases", "It stays the same", "It becomes zero"]', 'A', 'When a sound source moves toward a listener (Doppler effect), the frequency heard increases (pitch rises) because sound waves are compressed.', 'Science', 'Physics', 'hard', 'secondary'),
('What is the speed of light in a vacuum?', '["3 × 10⁸ m/s", "3 × 10⁶ m/s", "3 × 10¹⁰ m/s", "3 × 10⁴ m/s"]', 'A', 'The speed of light in a vacuum is approximately 3 × 10⁸ m/s (300,000 km/s), denoted by the symbol c.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the formula for work done by a force?', '["W = F × d", "W = F / d", "W = F + d", "W = F × t"]', 'A', 'Work = Force × displacement (in the direction of force): W = Fd. The unit of work is the joule (J).', 'Science', 'Physics', 'easy', 'secondary'),
('What type of wave requires a medium to travel through?', '["Mechanical wave", "Electromagnetic wave", "Radio wave", "Light wave"]', 'A', 'Mechanical waves (like sound waves, water waves) require a medium (solid, liquid, or gas) to propagate. Electromagnetic waves can travel through a vacuum.', 'Science', 'Physics', 'medium', 'secondary'),
('The law of conservation of energy states that energy can be:', '["Neither created nor destroyed, only transformed", "Created but not destroyed", "Destroyed but not created", "Created and destroyed equally"]', 'A', 'The law of conservation of energy states that energy cannot be created or destroyed; it can only be transformed from one form to another.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the term for the total distance divided by total time?', '["Average speed", "Instantaneous speed", "Velocity", "Acceleration"]', 'A', 'Average speed = total distance / total time. Unlike instantaneous speed, it considers the entire journey.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the SI unit of electrical current?', '["Ampere (A)", "Volt (V)", "Ohm (Ω)", "Watt (W)"]', 'A', 'The ampere (A) is the SI unit of electric current, measuring the rate of flow of electric charge (coulombs per second).', 'Science', 'Physics', 'easy', 'secondary'),
('What is the difference between speed and velocity?', '["Velocity includes direction; speed does not", "Speed includes direction; velocity does not", "They are the same", "Velocity is faster than speed"]', 'A', 'Velocity is a vector quantity that includes both magnitude (speed) and direction. Speed is a scalar quantity with only magnitude.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the phenomenon where light bends as it passes from one medium to another?', '["Refraction", "Reflection", "Diffraction", "Absorption"]', 'A', 'Refraction is the bending of light (or other waves) as it passes from one medium to another with a different density/refractive index.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the unit of frequency?', '["Hertz (Hz)", "Meter (m)", "Second (s)", "Newton (N)"]', 'A', 'The hertz (Hz) is the unit of frequency, measuring the number of complete cycles per second (1 Hz = 1 cycle/second).', 'Science', 'Physics', 'easy', 'secondary'),
('What is the gravitational acceleration on Earth''s surface (approximate)?', '["9.8 m/s²", "9.8 m/s", "9.8 km/s", "9.8 N"]', 'A', 'The acceleration due to gravity on Earth''s surface is approximately 9.8 m/s² (often rounded to 10 m/s² for calculations).', 'Science', 'Physics', 'easy', 'secondary'),
('What type of circuit provides multiple paths for current to flow?', '["Parallel circuit", "Series circuit", "Open circuit", "Short circuit"]', 'A', 'In a parallel circuit, components are connected across multiple branches, providing multiple paths for current flow. If one branch breaks, others continue working.', 'Science', 'Physics', 'medium', 'secondary'),
('What property of matter determines its resistance to changes in motion?', '["Inertia", "Momentum", "Velocity", "Acceleration"]', 'A', 'Inertia is the property of matter that causes it to resist changes in its state of motion. Greater mass means greater inertia.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the formula for momentum?', '["p = mv", "p = ma", "p = Fd", "p = W/t"]', 'A', 'Momentum = mass × velocity (p = mv). Momentum is a vector quantity, measured in kg·m/s.', 'Science', 'Physics', 'medium', 'secondary'),
('Which color of visible light has the highest frequency?', '["Violet", "Red", "Green", "Yellow"]', 'A', 'Violet light has the highest frequency (and shortest wavelength) in the visible spectrum. Red has the lowest frequency.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the term for heat transfer through direct contact?', '["Conduction", "Convection", "Radiation", "Insulation"]', 'A', 'Conduction is heat transfer through direct contact between materials. Convection involves fluid movement; radiation involves electromagnetic waves.', 'Science', 'Physics', 'easy', 'secondary'),
('What happens to resistance when temperature increases in a metallic conductor?', '["Resistance increases", "Resistance decreases", "Resistance stays the same", "Resistance becomes zero"]', 'A', 'In metallic conductors, resistance generally increases with temperature because increased thermal energy causes more collisions between electrons and atoms.', 'Science', 'Physics', 'hard', 'secondary'),
('What is the term for the tendency of an object to continue in its state of rest or motion?', '["Inertia", "Momentum", "Force", "Gravity"]', 'A', 'Inertia (from Newton''s First Law) is the tendency of an object to remain at rest or in uniform motion unless acted upon by an external force.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the wavelength of a wave with frequency 500 Hz and speed 340 m/s?', '["0.68 m", "6.8 m", "0.068 m", "68 m"]', 'A', 'Wave speed = frequency × wavelength. So λ = v/f = 340/500 = 0.68 m.', 'Science', 'Physics', 'hard', 'secondary'),
('What is the SI unit of pressure?', '["Pascal (Pa)", "Newton (N)", "Joule (J)", "Bar"]', 'A', 'The pascal (Pa) is the SI unit of pressure: 1 Pa = 1 N/m². Named after Blaise Pascal who studied fluid pressure.', 'Science', 'Physics', 'easy', 'secondary'),
('In a series circuit, if one bulb burns out:', '["All bulbs go out", "Other bulbs stay on", "Bulbs become brighter", "Current increases"]', 'A', 'In a series circuit, components share a single path. If one component breaks, the circuit is interrupted and all components stop working.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the formula for electrical power?', '["P = IV", "P = I/V", "P = I + V", "P = V/I"]', 'A', 'Electrical power = current × voltage (P = IV). Combined with Ohm''s Law: P = I²R = V²/R.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the term for the bouncing back of light from a surface?', '["Reflection", "Refraction", "Absorption", "Transmission"]', 'A', 'Reflection is the bouncing back of light (or other waves) from a surface. The angle of incidence equals the angle of reflection.', 'Science', 'Physics', 'easy', 'secondary'),
('What force keeps planets in orbit around the sun?', '["Gravity", "Friction", "Electromagnetism", "Nuclear force"]', 'A', 'Gravity (gravitational force) keeps planets in orbit around the sun, acting as the centripetal force for their orbital motion.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the acceleration of an object if its velocity changes from 10 m/s to 30 m/s in 4 seconds?', '["5 m/s²", "10 m/s²", "7.5 m/s²", "20 m/s²"]', 'A', 'Acceleration = (final velocity - initial velocity) / time = (30 - 10) / 4 = 20 / 4 = 5 m/s².', 'Science', 'Physics', 'medium', 'secondary'),
('What type of lens is thicker in the middle than at the edges?', '["Convex lens", "Concave lens", "Flat lens", "Bifocal lens"]', 'A', 'A convex (converging) lens is thicker at the center than edges. It converges light rays to a focal point.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the law of conservation of momentum?', '["The total momentum of a closed system remains constant", "Momentum is always zero", "Faster objects have more mass", "Momentum equals force times time"]', 'A', 'The law of conservation of momentum states that the total momentum of a closed system (no external forces) remains constant before and after a collision.', 'Science', 'Physics', 'medium', 'secondary'),
('What type of heat transfer occurs in fluids (liquids and gases)?', '["Convection", "Conduction", "Radiation", "Evaporation"]', 'A', 'Convection is heat transfer through the movement of fluids (liquids and gases). Hot fluid rises and cool fluid sinks, creating convection currents.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the energy stored in a compressed spring called?', '["Elastic potential energy", "Kinetic energy", "Chemical energy", "Gravitational potential energy"]', 'A', 'Elastic potential energy is stored in objects that have been stretched or compressed (like springs, rubber bands), given by PE = ½kx².', 'Science', 'Physics', 'medium', 'secondary'),
('What is the formula for weight?', '["W = mg", "W = m/g", "W = m + g", "W = ma²"]', 'A', 'Weight = mass × gravitational acceleration (W = mg). Weight is measured in newtons (N), while mass is in kilograms.', 'Science', 'Physics', 'easy', 'secondary'),
('In which medium does sound travel fastest?', '["Solids", "Liquids", "Gases", "Vacuum"]', 'A', 'Sound travels fastest through solids because particles are closely packed. It travels slower through liquids and slowest through gases (it cannot travel through vacuum).', 'Science', 'Physics', 'medium', 'secondary'),
('What is the relationship between wavelength and frequency of a wave?', '["Inversely proportional", "Directly proportional", "No relationship", "Exponentially related"]', 'A', 'Wavelength and frequency are inversely proportional: λ = v/f. As frequency increases, wavelength decreases (at constant wave speed).', 'Science', 'Physics', 'medium', 'secondary'),
('What type of mirror is used in vehicle rear-view mirrors?', '["Convex mirror", "Concave mirror", "Plane mirror", "Parabolic mirror"]', 'A', 'Convex (diverging) mirrors are used in rear-view mirrors because they produce a wider field of view, though images appear smaller than actual objects.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the unit of power?', '["Watt (W)", "Joule (J)", "Newton (N)", "Ampere (A)"]', 'A', 'The watt (W) is the SI unit of power, equal to one joule per second (1 W = 1 J/s). Named after James Watt.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the phenomenon where a material emits electrons when exposed to light?', '["Photoelectric effect", "Refraction", "Electromagnetic induction", "Diffraction"]', 'A', 'The photoelectric effect is the emission of electrons from a material when it absorbs electromagnetic radiation (light). Explained by Einstein in 1905.', 'Science', 'Physics', 'hard', 'secondary'),
('What is the SI unit of magnetic flux density?', '["Tesla (T)", "Ohm (Ω)", "Volt (V)", "Weber (Wb)"]', 'A', 'The tesla (T) is the SI unit of magnetic flux density (magnetic field strength). Named after Nikola Tesla.', 'Science', 'Physics', 'hard', 'secondary'),
('If a 5 kg object is lifted 3 meters, how much gravitational potential energy does it gain? (g = 10 m/s²)', '["150 J", "15 J", "50 J", "30 J"]', 'A', 'Gravitational PE = mgh = 5 × 10 × 3 = 150 joules.', 'Science', 'Physics', 'medium', 'secondary'),
('What does a transformer do in an electrical circuit?', '["Changes the voltage level of AC", "Converts AC to DC", "Stores electrical energy", "Measures current"]', 'A', 'A transformer changes (steps up or steps down) the voltage level of alternating current (AC) using electromagnetic induction.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the kinetic energy of a 2 kg object moving at 4 m/s?', '["16 J", "8 J", "32 J", "4 J"]', 'A', 'Kinetic energy = ½mv² = ½ × 2 × 4² = ½ × 2 × 16 = 16 joules.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the principle that states pressure applied to a confined fluid is transmitted equally in all directions?', '["Pascal''s Principle", "Archimedes'' Principle", "Newton''s Law", "Bernoulli''s Principle"]', 'A', 'Pascal''s Principle states that pressure applied to an enclosed fluid is transmitted undiminished to every part of the fluid. This is the basis of hydraulic systems.', 'Science', 'Physics', 'hard', 'secondary');
